CREATE OR REPLACE FUNCTION public.auto_pause_on_reply()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF (NEW.replied_at IS NOT NULL AND (OLD.replied_at IS NULL OR OLD.replied_at IS DISTINCT FROM NEW.replied_at))
     OR (NEW.dm_replied_at IS NOT NULL AND (OLD.dm_replied_at IS NULL OR OLD.dm_replied_at IS DISTINCT FROM NEW.dm_replied_at))
  THEN
    NEW.automation_paused := true;
    IF NEW.automation_paused_reason IS NULL THEN
      NEW.automation_paused_reason := 'replied_awaiting_human_response';
    END IF;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_tag_target_account()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_normalized TEXT;
  v_matched_id BIGINT;
  v_matched_name TEXT;
  v_best_fit TEXT;
  v_cohort_slug TEXT;
BEGIN
  -- Skip if no company, or already tagged
  IF NEW.company IS NULL OR NEW.company = '' OR NEW.target_account_priority IS NOT NULL THEN
    RETURN NEW;
  END IF;

  -- Normalize incoming company name (lowercase, alphanumeric only)
  v_normalized := LOWER(REGEXP_REPLACE(NEW.company, '[^a-zA-Z0-9]', '', 'g'));

  -- Skip if normalized name is too short to be meaningful
  IF LENGTH(v_normalized) < 3 THEN
    RETURN NEW;
  END IF;

  -- Match against target_accounts via prefix match (highest priority_score wins)
  SELECT id, company_name, best_fit_decision_record
    INTO v_matched_id, v_matched_name, v_best_fit
  FROM target_accounts
  WHERE active = TRUE
    AND (
      v_normalized = company_name_normalized
      OR v_normalized LIKE company_name_normalized || '%'
      OR company_name_normalized LIKE v_normalized || '%'
    )
  ORDER BY priority_score DESC NULLS LAST
  LIMIT 1;

  IF v_matched_id IS NOT NULL THEN
    -- Map the human-readable best_fit_decision_record to the cohort slug used by the drafter
    v_cohort_slug := CASE v_best_fit
      WHEN 'Batch Release Authorization'        THEN 'batch_release_cohort'
      WHEN 'Change Control Filing Determination' THEN 'change_control_cohort'
      WHEN 'Supplier Qualification Exception'    THEN 'supplier_qualification_cohort'
      WHEN 'Complaint Investigation Disposition' THEN 'complaint_investigation_cohort'
      WHEN 'Data Integrity Investigation Closure' THEN 'data_integrity_cohort'
      WHEN 'Deviation Risk Assessment'           THEN 'deviation_risk_cohort'
      WHEN 'CAPA Effectiveness'                  THEN 'capa_effectiveness_cohort'
      WHEN 'CAPA Effectiveness Determination'    THEN 'capa_effectiveness_cohort'
      ELSE 'batch_release_cohort'  -- fallback only if best_fit is unset/unknown
    END;

    NEW.target_account_priority := v_cohort_slug;
    NEW.target_account_tagged_at := NOW();
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.calculate_next_followup()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF NEW.last_sequence_email_at IS DISTINCT FROM OLD.last_sequence_email_at
     AND NEW.last_sequence_email_at IS NOT NULL
     AND NEW.replied_at IS NULL
     AND NEW.archived_at IS NULL
  THEN
    -- After touch N is sent (sequence_email_count = N), touch N+1 is what's due.
    -- Touch 1 sent → followup_2_due in 3 days
    -- Touch 2 sent → followup_3_due (breakup) in 4 days
    -- Touch 3 sent → sequence complete
    IF NEW.sequence_email_count = 1 THEN
      NEW.next_followup_due_at = NEW.last_sequence_email_at + INTERVAL '3 days';
      NEW.followup_stage = 'followup_2_due';
    ELSIF NEW.sequence_email_count = 2 THEN
      NEW.next_followup_due_at = NEW.last_sequence_email_at + INTERVAL '4 days';
      NEW.followup_stage = 'followup_3_due';
    ELSIF NEW.sequence_email_count = 3 THEN
      NEW.next_followup_due_at = NEW.last_sequence_email_at + INTERVAL '7 days';
      NEW.followup_stage = 'breakup_due';
    ELSE
      NEW.next_followup_due_at = NULL;
      NEW.followup_stage = 'sequence_complete';
    END IF;
  END IF;

  IF NEW.replied_at IS NOT NULL AND OLD.replied_at IS NULL THEN
    NEW.next_followup_due_at = NULL;
    NEW.followup_stage = 'replied';
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.claim_next_irr_job()
 RETURNS SETOF irr_jobs
 LANGUAGE plpgsql
AS $function$
declare
  claimed_id uuid;
begin
  select job_id into claimed_id
  from irr_jobs
  where status = 'queued'
  order by created_at asc
  limit 1
  for update skip locked;

  if claimed_id is null then
    return;
  end if;

  update irr_jobs
  set status = 'running', updated_at = now()
  where job_id = claimed_id;

  return query select * from irr_jobs where job_id = claimed_id;
end;
$function$

CREATE OR REPLACE FUNCTION public.claim_next_runtime_generation()
 RETURNS SETOF runtime_generations
 LANGUAGE plpgsql
AS $function$
DECLARE
  claimed_id uuid;
BEGIN
  SELECT generation_id INTO claimed_id
  FROM runtime_generations
  WHERE status = 'pending' AND claimed_at IS NULL
  ORDER BY created_at ASC
  LIMIT 1
  FOR UPDATE SKIP LOCKED;

  IF claimed_id IS NULL THEN
    RETURN;
  END IF;

  UPDATE runtime_generations
  SET claimed_at = now(), updated_at = now()
  WHERE generation_id = claimed_id;

  RETURN QUERY SELECT * FROM runtime_generations WHERE generation_id = claimed_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.compute_lead_readiness_blocks(row_id bigint)
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  r RECORD;
  blocks TEXT[] := ARRAY[]::TEXT[];
BEGIN
  SELECT
    linkedin_url, linkedin_headline, linkedin_description,
    job_title, full_name, company, first_name
  INTO r
  FROM warm_outbound_staging
  WHERE id = row_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_array('row_not_found');
  END IF;

  IF r.linkedin_url IS NULL OR length(trim(r.linkedin_url)) = 0 THEN
    blocks := array_append(blocks, 'missing_linkedin_url');
  END IF;

  IF r.linkedin_headline IS NULL OR length(trim(r.linkedin_headline)) = 0 THEN
    blocks := array_append(blocks, 'missing_linkedin_headline');
  END IF;

  IF r.linkedin_description IS NULL OR length(trim(r.linkedin_description)) < 50 THEN
    blocks := array_append(blocks, 'linkedin_description_too_short');
  END IF;

  IF r.job_title IS NULL OR length(trim(r.job_title)) = 0 THEN
    blocks := array_append(blocks, 'missing_job_title');
  END IF;

  IF r.first_name IS NULL OR length(trim(r.first_name)) = 0 THEN
    blocks := array_append(blocks, 'missing_first_name');
  END IF;

  IF r.company IS NULL OR length(trim(r.company)) = 0 THEN
    blocks := array_append(blocks, 'missing_company');
  END IF;

  RETURN to_jsonb(blocks);
END;
$function$

CREATE OR REPLACE FUNCTION public.detect_strategy_signals()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  signal_count int := 0;
  v_visitors_7d int; v_visitors_prev_7d int; v_visitors_change_pct numeric;
  v_captures_7d int; v_captures_prev_7d int; v_captures_change_pct numeric;
  v_touches_7d int; v_revenue_pace numeric; v_days_remaining int;
  v_paid_clicks_7d numeric; v_paid_clicks_prev_7d numeric;
  v_daily_intake int; v_dms_today int; v_hour_et int;
  rec RECORD;
BEGIN
  PERFORM refresh_key_results();

  -- Visitor trend
  SELECT count(DISTINCT session_id) INTO v_visitors_7d FROM events WHERE event_name = 'page_view' AND created_at >= now() - interval '7 days' AND session_id IS NOT NULL;
  SELECT count(DISTINCT session_id) INTO v_visitors_prev_7d FROM events WHERE event_name = 'page_view' AND created_at >= now() - interval '14 days' AND created_at < now() - interval '7 days' AND session_id IS NOT NULL;
  IF v_visitors_prev_7d > 0 THEN
    v_visitors_change_pct := ROUND(((v_visitors_7d - v_visitors_prev_7d)::numeric / v_visitors_prev_7d * 100), 0);
    IF v_visitors_change_pct <= -25 THEN
      INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) VALUES ('visitor_drop', 'critical',
        'Weekly visitors dropped ' || v_visitors_change_pct || '% (' || v_visitors_prev_7d || ' → ' || v_visitors_7d || ')',
        'Pipeline depends on visitor flow.', 'Check LinkedIn group post status. Concentrate distribution on Batch Release.')
      ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
      IF FOUND THEN signal_count := signal_count + 1; END IF;
    END IF;
  END IF;

  -- NEW: Phantombuster daily intake check
  SELECT count(*)::int INTO v_daily_intake FROM contacts 
  WHERE created_at >= CURRENT_DATE 
    AND email NOT LIKE '%@complianceworxs.com' 
    AND email NOT LIKE '%@coursworx.com';

  -- Only fire after 6 PM ET (22 UTC) to avoid morning false alarms
  v_hour_et := EXTRACT(HOUR FROM (now() AT TIME ZONE 'America/New_York'))::int;
  IF v_hour_et >= 18 AND v_daily_intake < 25 THEN
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) 
    VALUES ('phantombuster_intake_low', 'critical',
      'Phantombuster intake at ' || v_daily_intake || ' today (target 50/day, threshold 25)',
      'Daily new-contact intake from the Phantombuster pipeline (Sales Navigator Search Export, Profile Scraper, Group Members Export) is below half-target. The 12,000-prospect Sales Navigator search should be feeding 50/day at minimum.',
      'Check Phantombuster: verify all phantoms are ON, have remaining daily slots, and the Sales Navigator session cookie has not expired. Also check that incoming profiles are being written to the contacts table by the enrichment flow.')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END IF;

  -- NEW: Daily DM pace check
  SELECT count(*)::int INTO v_dms_today FROM outreach_touches 
  WHERE source_type='outbound' AND sent_at >= CURRENT_DATE;

  -- Only fire after 2 PM ET (18 UTC), warning if behind 10 by mid-afternoon
  IF v_hour_et >= 14 AND v_dms_today < 10 THEN
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) 
    VALUES ('daily_dm_pace_low', 'warning',
      'Only ' || v_dms_today || ' DMs sent today by ' || v_hour_et || ':00 ET (target 20/day)',
      'Past mid-afternoon with fewer than 10 outbound touches today. Pace puts the daily 20-DM target at risk.',
      'Pull next batch from outreach_queue: SELECT email_subject, email_body FROM outreach_queue WHERE trigger_reason LIKE ''staged_dm_v%'' AND status = ''pending'' LIMIT 10;')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END IF;

  -- Capture rate from PostHog cache
  SELECT metric_value::int INTO v_captures_7d FROM posthog_metric_cache WHERE metric_key = 'captures_7d';
  IF v_visitors_7d > 50 AND v_captures_7d = 0 THEN
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) VALUES ('zero_captures', 'critical',
      'Zero captures from ' || v_visitors_7d || ' visitors in last 7 days',
      'Form gate not converting.', 'Test the form yourself.')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END IF;

  -- Outbound pace (weekly)
  SELECT count(*) INTO v_touches_7d FROM outreach_touches WHERE source_type = 'outbound' AND sent_at >= now() - interval '7 days';
  IF v_touches_7d < 50 AND EXTRACT(DOW FROM CURRENT_DATE) >= 4 THEN  -- raised threshold from 15 to 50
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) VALUES ('outbound_slipping', 'warning',
      'Only ' || v_touches_7d || ' outbound touches this week (target 100/wk = 20/day x 5)',
      'New target: 20 DMs/day x 5 working days = 100/week. Pipeline can''t close what wasn''t opened.',
      'Pull and send next batch from outreach_queue. Phantombuster intake should be feeding fresh prospects daily.')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END IF;

  -- Revenue pace
  v_days_remaining := GREATEST(0, EXTRACT(EPOCH FROM ('2026-06-01'::timestamp - now())) / 86400)::int;
  SELECT GREATEST(0, (1500 - coalesce(sum(amount_cents),0)/100.0)) / GREATEST(1, v_days_remaining) INTO v_revenue_pace
    FROM orders WHERE order_status='completed' AND refunded_at IS NULL AND purchased_at >= '2026-05-01' AND purchased_at < '2026-06-01';
  IF v_revenue_pace > 100 THEN
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) VALUES ('revenue_pace_high', 'warning',
      'Required daily revenue pace: $' || ROUND(v_revenue_pace, 0)::text || '/day (' || v_days_remaining || ' days remaining)',
      'May target requires escalating effort.', 'Close one $149-$297 sale this week, or revise May target.')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END IF;

  -- Unworked leads (existing)
  FOR rec IN
    SELECT c.id, c.email, c.first_name, c.company, c.job_title, c.created_at FROM contacts c
    WHERE c.lifecycle_stage = 'lead' AND c.created_at < now() - interval '5 days'
      AND c.email NOT LIKE '%@complianceworxs.com' AND c.email NOT LIKE '%@coursworx.com'
      AND NOT EXISTS (SELECT 1 FROM outreach_touches ot WHERE ot.target_email = c.email AND ot.sent_at >= c.created_at)
    ORDER BY c.created_at DESC LIMIT 20
  LOOP
    INSERT INTO strategy_signals (signal_type, severity, title, detail, suggested_action) VALUES ('unworked_lead', 'warning',
      'Unworked lead: ' || coalesce(rec.first_name, '') || ' ' || coalesce(rec.job_title, '') || ' at ' || coalesce(rec.company, '(unknown)') || ' — ' || rec.email,
      'Captured ' || ROUND(EXTRACT(EPOCH FROM (now() - rec.created_at))/86400) || ' days ago, no follow-up sent.',
      'DM or email this person.')
    ON CONFLICT (signal_type, title) WHERE resolved_at IS NULL DO NOTHING;
    IF FOUND THEN signal_count := signal_count + 1; END IF;
  END LOOP;

  RETURN signal_count;
END;
$function$

CREATE OR REPLACE FUNCTION public.dm_send_eligibility(p_outreach_queue_id uuid)
 RETURNS TABLE(eligible boolean, reason text, q_email text, q_first_name text, q_last_name text, q_company text, q_job_title text, q_linkedin_url text, q_email_subject text, q_email_body text, q_case_file text)
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  q RECORD;
  c RECORD;
  v_domain text;
  v_company_lower text;
  v_title_lower text;
  v_passes_audience boolean := false;
  v_passes_title_block boolean := true;
  v_recent_touch_count int;
  v_paid_count int;
  v_replied_count int;
BEGIN
  -- Pull the queue row
  SELECT * INTO q FROM outreach_queue WHERE id = p_outreach_queue_id;
  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'queue_row_not_found', NULL::text, NULL::text, NULL::text, NULL::text, NULL::text, NULL::text, NULL::text, NULL::text, NULL::text;
    RETURN;
  END IF;

  -- Pull the contact
  SELECT * INTO c FROM contacts WHERE normalized_email = lower(q.email);
  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 'contact_not_found', q.email, NULL::text, NULL::text, NULL::text, NULL::text, NULL::text, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- FILTER 1: Identity completeness
  IF c.first_name IS NULL OR length(trim(c.first_name)) < 2 THEN
    RETURN QUERY SELECT false, 'no_first_name', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;
  IF c.linkedin_url IS NULL OR c.linkedin_url = '' THEN
    RETURN QUERY SELECT false, 'no_linkedin_url', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;
  IF c.company IS NULL OR length(trim(c.company)) < 2 THEN
    RETURN QUERY SELECT false, 'no_company', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  v_domain := lower(split_part(q.email, '@', 2));
  v_company_lower := lower(coalesce(c.company, ''));
  v_title_lower := lower(coalesce(c.job_title, ''));

  -- FILTER 2a: Domain blocklist (always reject)
  IF EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'domain_block' AND lower(value) = v_domain) THEN
    RETURN QUERY SELECT false, 'blocked_personal_domain:' || v_domain, q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- FILTER 2b: Title blocklist (always reject if title contains blocked term)
  IF v_title_lower != '' THEN
    IF EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'title_block' AND v_title_lower LIKE '%' || lower(value) || '%') THEN
      RETURN QUERY SELECT false, 'blocked_title:' || v_title_lower, q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
      RETURN;
    END IF;
  END IF;

  -- FILTER 2c: Audience fit — pass if any of these is true:
  --   (a) Email domain on pharma allowlist
  --   (b) Company name contains a pharma keyword
  --   (c) Domain contains a pharma keyword
  --   (d) Job title contains an allowed compliance signal
  IF EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'pharma_domain' AND lower(value) = v_domain) THEN
    v_passes_audience := true;
  ELSIF EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'pharma_keyword' AND v_company_lower LIKE '%' || lower(value) || '%') THEN
    v_passes_audience := true;
  ELSIF EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'pharma_keyword' AND v_domain LIKE '%' || lower(value) || '%') THEN
    v_passes_audience := true;
  ELSIF v_title_lower != '' AND EXISTS (SELECT 1 FROM dm_audience_signals WHERE signal_type = 'title_allow' AND v_title_lower LIKE '%' || lower(value) || '%') THEN
    v_passes_audience := true;
  END IF;

  IF NOT v_passes_audience THEN
    RETURN QUERY SELECT false, 'audience_review_required', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- FILTER 3a: Cooldown — no DM/email touch in last N hours
  SELECT count(*) INTO v_recent_touch_count
  FROM outreach_touches
  WHERE target_email = q.email
    AND sent_at >= now() - ((SELECT cooldown_hours FROM dm_automation_config WHERE id=1)::text || ' hours')::interval
    AND channel IN ('linkedin_dm', 'email');
  IF v_recent_touch_count > 0 THEN
    RETURN QUERY SELECT false, 'cooldown_active:' || v_recent_touch_count || '_recent_touches', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- FILTER 3b: Already paying customer
  SELECT count(*) INTO v_paid_count FROM orders 
  WHERE contact_id = c.id AND order_status = 'completed' AND refunded_at IS NULL;
  IF v_paid_count > 0 THEN
    RETURN QUERY SELECT false, 'is_paying_customer', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- FILTER 3c: Already replied to a previous touch
  SELECT count(*) INTO v_replied_count FROM outreach_touches
  WHERE target_email = q.email AND reply_received = true;
  IF v_replied_count > 0 THEN
    RETURN QUERY SELECT false, 'already_replied', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
    RETURN;
  END IF;

  -- ALL FILTERS PASSED
  RETURN QUERY SELECT true, 'eligible', q.email, c.first_name, c.last_name, c.company, c.job_title, c.linkedin_url, q.email_subject, q.email_body, q.case_file;
END;
$function$

CREATE OR REPLACE FUNCTION public.enroll_from_link_click(p_email text, p_page_url text, p_user_agent text DEFAULT NULL::text, p_ip_address text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_staging_id    bigint;
  v_slug          text;
  v_mapped_cohort text;
  v_lead          RECORD;
  v_enroll_result jsonb;
  v_log_id        bigint;
  v_result_label  text;
  v_enrollment_id bigint;
  v_existing_active bigint;
BEGIN
  IF p_email IS NULL OR p_email = '' THEN
    INSERT INTO nurture_link_click_log (email, page_url, result, result_detail, user_agent, ip_address)
    VALUES (p_email, p_page_url, 'error',
            jsonb_build_object('error', 'no_email_provided'),
            p_user_agent, p_ip_address);
    RETURN jsonb_build_object('ok', false, 'reason', 'no_email_provided');
  END IF;

  v_slug := extract_case_file_slug(p_page_url);

  IF v_slug IS NOT NULL THEN
    SELECT cohort INTO v_mapped_cohort FROM case_file_cohort_map WHERE page_slug = v_slug;
  END IF;

  SELECT id, full_name, email, case_file_interest, target_account_priority,
         is_paying_customer, automation_paused
    INTO v_lead
  FROM warm_outbound_staging
  WHERE lower(email) = lower(p_email)
  ORDER BY id DESC
  LIMIT 1;

  IF NOT FOUND THEN
    INSERT INTO nurture_link_click_log (email, page_url, page_slug, result, result_detail, user_agent, ip_address)
    VALUES (p_email, p_page_url, v_slug, 'no_staging_match',
            jsonb_build_object('email', p_email),
            p_user_agent, p_ip_address);
    RETURN jsonb_build_object('ok', false, 'reason', 'no_staging_match', 'email', p_email);
  END IF;

  v_staging_id := v_lead.id;

  IF v_lead.is_paying_customer THEN
    INSERT INTO nurture_link_click_log (email, page_url, page_slug, staging_id, result, result_detail, user_agent, ip_address)
    VALUES (p_email, p_page_url, v_slug, v_staging_id, 'is_paying_customer',
            jsonb_build_object('staging_id', v_staging_id),
            p_user_agent, p_ip_address);
    RETURN jsonb_build_object('ok', false, 'reason', 'is_paying_customer', 'staging_id', v_staging_id);
  END IF;

  -- CHECK FOR ACTIVE ENROLLMENT FIRST (before mutating anything)
  SELECT id INTO v_existing_active
  FROM nurture_enrollments
  WHERE staging_id = v_staging_id AND status = 'active'
  LIMIT 1;

  IF v_existing_active IS NOT NULL THEN
    INSERT INTO nurture_link_click_log
      (email, page_url, page_slug, staging_id, enrollment_id, result, result_detail, user_agent, ip_address)
    VALUES
      (p_email, p_page_url, v_slug, v_staging_id, v_existing_active, 'already_enrolled',
       jsonb_build_object('enrollment_id', v_existing_active, 'reason', 'already_enrolled'),
       p_user_agent, p_ip_address)
    RETURNING id INTO v_log_id;

    RETURN jsonb_build_object(
      'ok', false,
      'reason', 'already_enrolled',
      'enrollment_id', v_existing_active,
      'staging_id', v_staging_id,
      'page_slug', v_slug,
      'log_id', v_log_id
    );
  END IF;

  -- Only NOW write the case_file_interest, since we know we're proceeding to enroll
  IF v_mapped_cohort IS NOT NULL THEN
    UPDATE warm_outbound_staging
    SET case_file_interest = v_mapped_cohort
    WHERE id = v_staging_id;
  END IF;

  v_enroll_result := enroll_in_nurture(
    v_staging_id,
    'link_click',
    'clicked: ' || COALESCE(p_page_url, '(no url)')
  );

  IF (v_enroll_result->>'ok')::boolean THEN
    v_result_label := 'enrolled';
    v_enrollment_id := (v_enroll_result->>'enrollment_id')::bigint;
  ELSIF v_enroll_result->>'reason' = 'suppressed' THEN
    v_result_label := 'suppressed';
  ELSIF v_enroll_result->>'reason' = 'already_customer' THEN
    v_result_label := 'is_paying_customer';
  ELSE
    v_result_label := 'error';
  END IF;

  INSERT INTO nurture_link_click_log
    (email, page_url, page_slug, staging_id, enrollment_id, result, result_detail, user_agent, ip_address)
  VALUES
    (p_email, p_page_url, v_slug, v_staging_id, v_enrollment_id, v_result_label, v_enroll_result, p_user_agent, p_ip_address)
  RETURNING id INTO v_log_id;

  RETURN v_enroll_result || jsonb_build_object(
    'log_id', v_log_id,
    'staging_id', v_staging_id,
    'page_slug', v_slug,
    'mapped_cohort', v_mapped_cohort
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.enroll_on_link_click(p_email text, p_url text, p_case_file_slug text DEFAULT NULL::text)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_staging_id bigint;
BEGIN
  IF p_email IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'no_email_provided');
  END IF;

  -- Find the most recent matching staging row
  SELECT id INTO v_staging_id
  FROM warm_outbound_staging
  WHERE lower(email) = lower(p_email)
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_staging_id IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'email_not_in_staging', 'email', p_email);
  END IF;

  -- If a case file slug came in via the click event, refine the cohort hint on the staging row
  -- (only if the row doesn't already have an interest set — preserve original targeting)
  IF p_case_file_slug IS NOT NULL THEN
    UPDATE warm_outbound_staging
    SET case_file_interest = COALESCE(case_file_interest, p_case_file_slug)
    WHERE id = v_staging_id;
  END IF;

  RETURN enroll_in_nurture(v_staging_id, 'link_click', 'url=' || COALESCE(p_url, 'unknown'));
END;
$function$

CREATE OR REPLACE FUNCTION public.evaluate_lead_readiness(row_id bigint)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  blocks JSONB;
  block_count INT;
  current_status TEXT;
  current_attempts INT;
  new_status TEXT;
BEGIN
  blocks := compute_lead_readiness_blocks(row_id);
  block_count := jsonb_array_length(blocks);

  SELECT readiness_status, COALESCE(readiness_attempts, 0)
  INTO current_status, current_attempts
  FROM warm_outbound_staging
  WHERE id = row_id;

  IF block_count = 0 THEN
    -- All fields present. Lead is ready for personalization.
    new_status := 'ready';
    UPDATE warm_outbound_staging
    SET readiness_status = new_status,
        readiness_checked_at = NOW(),
        readiness_block_reasons = blocks,
        readiness_retry_due_at = NULL
    WHERE id = row_id;
  ELSE
    -- Missing data. Decide between pending_retry and failed_enrichment.
    IF current_attempts = 0 THEN
      -- First failure: schedule a retry in 48 hours.
      new_status := 'pending_retry';
      UPDATE warm_outbound_staging
      SET readiness_status = new_status,
          readiness_checked_at = NOW(),
          readiness_block_reasons = blocks,
          readiness_attempts = 1,
          readiness_retry_due_at = NOW() + INTERVAL '48 hours'
      WHERE id = row_id;
    ELSE
      -- Second (or later) failure: archive.
      new_status := 'failed_enrichment';
      UPDATE warm_outbound_staging
      SET readiness_status = new_status,
          readiness_checked_at = NOW(),
          readiness_block_reasons = blocks,
          readiness_attempts = current_attempts + 1,
          readiness_failed_at = NOW(),
          archived_at = NOW(),
          archive_reason = 'enrichment_failed_after_retry'
      WHERE id = row_id;
    END IF;
  END IF;

  RETURN new_status;
END;
$function$

CREATE OR REPLACE FUNCTION public.exec_optimization_query(sql text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  result jsonb;
BEGIN
  -- Block obvious mutations
  IF sql ~* '\m(insert|update|delete|drop|truncate|alter|create|grant|revoke)\M' THEN
    RAISE EXCEPTION 'Mutation queries not allowed in exec_optimization_query';
  END IF;

  EXECUTE 'SELECT to_jsonb(coalesce(jsonb_agg(t), ''[]''::jsonb)) FROM (' || sql || ') t' INTO result;
  RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION public.extract_case_file_slug(p_url text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
DECLARE
  v_slug text;
BEGIN
  IF p_url IS NULL OR p_url = '' THEN
    RETURN NULL;
  END IF;

  -- Match cases.complianceworxs.com/<slug> or complianceworxs.com/<slug>
  -- Pull the first path segment after the host.
  v_slug := lower(regexp_replace(
    p_url,
    '^https?://[^/]*complianceworxs\.com/([a-z0-9\-]+).*$',
    '\1',
    'i'
  ));

  -- If regex didn't match (returned the whole URL), give up
  IF v_slug = lower(p_url) OR v_slug = '' THEN
    RETURN NULL;
  END IF;

  RETURN v_slug;
END;
$function$

