CREATE OR REPLACE FUNCTION public.set_optimizer_config(p_key text, p_new_value jsonb, p_reasoning text, p_reversal_trigger text DEFAULT NULL::text, p_executed boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_old jsonb;
  v_mode text;
BEGIN
  SELECT value INTO v_old FROM optimizer_config WHERE key = p_key;
  v_mode := (SELECT value::text FROM optimizer_config WHERE key = 'optimizer_mode');

  INSERT INTO optimizer_decisions (
    mode, stage, parameter_changed, old_value, new_value,
    reasoning, reversal_trigger, executed
  ) VALUES (
    REPLACE(v_mode, '"', ''), 'execute', p_key, v_old, p_new_value,
    p_reasoning, p_reversal_trigger, p_executed
  );

  IF p_executed THEN
    UPDATE optimizer_config
       SET value = p_new_value,
           updated_at = now(),
           updated_by = 'outbound-optimizer',
           reasoning = p_reasoning
     WHERE key = p_key;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.stream_outbound_event_to_posthog()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_posthog_key TEXT := 'phc_pYjwPXihpZPL8MaS86gxmEZMXvi3ZsvKdWuqZzLQEjt7';
  v_payload JSONB;
  v_distinct_id TEXT;
  v_request_id BIGINT;
BEGIN
  -- Use email as distinct_id when available, else staging_id, else event id
  v_distinct_id := COALESCE(NEW.email, 'staging_' || NEW.staging_id::text, 'event_' || NEW.id::text);

  v_payload := jsonb_build_object(
    'api_key', v_posthog_key,
    'event', NEW.event_name,
    'distinct_id', v_distinct_id,
    'timestamp', NEW.created_at,
    'properties', COALESCE(NEW.properties, '{}'::jsonb) || jsonb_build_object(
      '$event_uuid', NEW.id::text,
      'staging_id', NEW.staging_id,
      'attio_record_id', NEW.attio_record_id,
      'provider', NEW.provider,
      'email', NEW.email,
      'source', 'cw_outbound_pipeline'
    )
  );

  BEGIN
    SELECT net.http_post(
      url := 'https://us.i.posthog.com/capture/',
      body := v_payload,
      headers := jsonb_build_object('Content-Type', 'application/json'),
      timeout_milliseconds := 5000
    ) INTO v_request_id;

    -- Mark synced so the legacy posthog-sync cron skips it (defensive double-up guard)
    -- Use a separate UPDATE to avoid recursion since this trigger is on outbound_events
    UPDATE outbound_events
       SET posthog_synced_at = NOW(), posthog_request_id = v_request_id
     WHERE id = NEW.id;
  EXCEPTION WHEN OTHERS THEN
    -- Don't block the insert; only log
    RAISE NOTICE 'PostHog stream failed for event %: %', NEW.id, SQLERRM;
  END;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.suppress_buyer_in_mailerlite()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_email text;
BEGIN
